import scala.xml._
import scala.util.{Try, Success, Failure}
import java.io.StringReader
import javax.xml.parsers.SAXParserFactory
import org.xml.sax.InputSource

case class ConfigurationSettings(
  properties: Map[String, String],
  databases: List[DatabaseConfig],
  services: List[ServiceConfig],
  features: Map[String, Boolean]
)

case class DatabaseConfig(
  name: String,
  url: String,
  username: String,
  password: String,
  poolSize: Int
)

case class ServiceConfig(
  name: String,
  endpoint: String,
  timeout: Int,
  retries: Int
)

class ConfigurationParserService {

  def parseConfiguration(xmlContent: String): Try[ConfigurationSettings] = {
    Try {
      val xml = loadXmlSecurely(xmlContent)
      extractSettings(xml)
    }
  }

  private def loadXmlSecurely(xmlContent: String): Elem = {
    val factory = SAXParserFactory.newInstance()
    factory.setFeature("http://xml.org/sax/features/external-general-entities", false)
    factory.setFeature("http://xml.org/sax/features/external-parameter-entities", false)
    factory.setFeature("http://apache.org/xml/features/disallow-doctype-decl", true)
    factory.setFeature("http://apache.org/xml/features/nonvalidating/load-external-dtd", false)
    factory.setXIncludeAware(false)
    
    val parser = factory.newSAXParser()
    val adapter = new scala.xml.parsing.NoBindingFactoryAdapter
    val source = new InputSource(new StringReader(xmlContent))
    adapter.loadXML(source, parser)
  }

  private def extractSettings(xml: Elem): ConfigurationSettings = {
    val properties = extractProperties(xml)
    val databases = extractDatabases(xml)
    val services = extractServices(xml)
    val features = extractFeatures(xml)

    ConfigurationSettings(properties, databases, services, features)
  }

  private def extractProperties(xml: Elem): Map[String, String] = {
    (xml \ "properties" \ "property").map { node =>
      val key = (node \ "@key").text
      val value = (node \ "@value").text
      key -> value
    }.toMap
  }

  private def extractDatabases(xml: Elem): List[DatabaseConfig] = {
    (xml \ "databases" \ "database").map { node =>
      DatabaseConfig(
        name = (node \ "@name").text,
        url = (node \ "url").text,
        username = (node \ "username").text,
        password = (node \ "password").text,
        poolSize = (node \ "poolSize").text.toIntOption.getOrElse(10)
      )
    }.toList
  }

  private def extractServices(xml: Elem): List[ServiceConfig] = {
    (xml \ "services" \ "service").map { node =>
      ServiceConfig(
        name = (node \ "@name").text,
        endpoint = (node \ "endpoint").text,
        timeout = (node \ "timeout").text.toIntOption.getOrElse(30000),
        retries = (node \ "retries").text.toIntOption.getOrElse(3)
      )
    }.toList
  }

  private def extractFeatures(xml: Elem): Map[String, Boolean] = {
    (xml \ "features" \ "feature").map { node =>
      val name = (node \ "@name").text
      val enabled = (node \ "@enabled").text.toBooleanOption.getOrElse(false)
      name -> enabled
    }.toMap
  }
}

class ConfigurationApiHandler {
  private val parser = new ConfigurationParserService()

  def handleConfigurationRequest(xmlPayload: String): Either[String, ConfigurationSettings] = {
    if (xmlPayload == null || xmlPayload.trim.isEmpty) {
      return Left("Empty XML payload")
    }

    parser.parseConfiguration(xmlPayload) match {
      case Success(settings) => Right(settings)
      case Failure(ex) => Left(s"Failed to parse configuration: ${ex.getMessage}")
    }
  }

  def validateAndParse(xmlPayload: String): Either[String, ConfigurationSettings] = {
    for {
      _ <- validateXmlSize(xmlPayload)
      _ <- validateXmlStructure(xmlPayload)
      settings <- handleConfigurationRequest(xmlPayload)
    } yield settings
  }

  private def validateXmlSize(xmlPayload: String): Either[String, Unit] = {
    val maxSize = 1024 * 1024
    if (xmlPayload.length > maxSize) {
      Left(s"XML payload exceeds maximum size of $maxSize bytes")
    } else {
      Right(())
    }
  }

  private def validateXmlStructure(xmlPayload: String): Either[String, Unit] = {
    if (!xmlPayload.trim.startsWith("<")) {
      Left("Invalid XML structure")
    } else {
      Right(())
    }
  }
}

object ConfigurationService {
  def apply(): ConfigurationApiHandler = new ConfigurationApiHandler()

  def parseFromString(xmlContent: String): Try[ConfigurationSettings] = {
    val service = new ConfigurationParserService()
    service.parseConfiguration(xmlContent)
  }
}

class ConfigurationManager {
  private val handler = ConfigurationService()
  private var currentConfig: Option[ConfigurationSettings] = None

  def loadConfiguration(xmlContent: String): Either[String, ConfigurationSettings] = {
    handler.validateAndParse(xmlContent) match {
      case Right(settings) =>
        currentConfig = Some(settings)
        Right(settings)
      case Left(error) => Left(error)
    }
  }

  def getCurrentConfiguration: Option[ConfigurationSettings] = currentConfig

  def getProperty(key: String): Option[String] = {
    currentConfig.flatMap(_.properties.get(key))
  }

  def getDatabaseConfig(name: String): Option[DatabaseConfig] = {
    currentConfig.flatMap(_.databases.find(_.name == name))
  }

  def getServiceConfig(name: String): Option[ServiceConfig] = {
    currentConfig.flatMap(_.services.find(_.name == name))
  }

  def isFeatureEnabled(feature: String): Boolean = {
    currentConfig.flatMap(_.features.get(feature)).getOrElse(false)
  }

  def reloadConfiguration(xmlContent: String): Either[String, Unit] = {
    loadConfiguration(xmlContent).map(_ => ())
  }
}

object ConfigurationManagerApp {
  def main(args: Array[String]): Unit = {
    val manager = new ConfigurationManager()
    
    val sampleXml = """<?xml version="1.0" encoding="UTF-8"?>
