        </properties>
        <databases>
          <database name="primary">
            <url>jdbc:postgresql://localhost:5432/mydb</url>
            <username>dbuser</username>
            <password>dbpass</password>
            <poolSize>20</poolSize>
          </database>
          <database name="cache">
            <url>jdbc:redis://localhost:6379</url>
            <username>redisuser</username>
            <password>redispass</password>
            <poolSize>10</poolSize>
          </database>
        </databases>
        <services>
          <service name="authService">
            <endpoint>https://auth.example.com/api</endpoint>
            <timeout>5000</timeout>
            <retries>3</retries>
          </service>
          <service name="paymentService">
            <endpoint>https://payment.example.com/api</endpoint>
            <timeout>10000</timeout>
            <retries>5</retries>
          </service>
        </services>
        <features>
          <feature name="newUI" enabled="true"/>
          <feature name="betaFeatures" enabled="false"/>
          <feature name="analytics" enabled="true"/>
        </features>
      </configuration>"""
    
    manager.loadConfiguration(sampleXml) match {
      case Right(config) =>
        println(s"Configuration loaded successfully")
